mapper.sql:
and a.store_id = #{storeId}
and a.recycle = 0
AND a.mch_id = #{mchId} AND a.supplier_superior is not null
AND a.mch_id = 0
AND (a.product_title like CONCAT('%',#{condition},'%') or a.id = #{condition} or b.supplier_name = #{condition})
AND a.id = #{goodsId}
AND b.supplier_name like CONCAT('%',#{supplierName},'%')
AND (b.supplier_name like CONCAT('%',#{supplierKey},'%') or a.id = #{supplierKey} or a.product_title like CONCAT('%',#{supplierKey},'%'))
AND a.product_title like CONCAT('%',#{productTitle},'%')
AND a.status = #{status}
AND a.supplier_status = #{supplier_status}

    
        #{status,jdbcType=INTEGER}
    

AND a.mch_status = #{mch_status}

    
        #{mch_status,jdbcType=INTEGER}
    

AND a.product_class like CONCAT('%-',#{product_class},'-%')
AND a.brand_id = #{brand_id}
and a.add_date   >=   #{startTime}
and a.add_date   <=   #{endTime}
and a.outage_time   >=   #{outageStartTime}
and a.outage_time   <=   #{outageEndTime}
and a.violation_time   >=   #{violationStartTime}
and a.violation_time   <=   #{violationEndTime}
and a.gongyingshang = #{supplierId}
and a.status != 4

mapper.select:
SELECT a.*,b.supplier_name FROM lkt_product_list a LEFT JOIN lkt_supplier b ON a.gongyingshang = b.id
a.examine_time ${examine_time_sort}, a.sort ${sort_sort}, add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}
